        const isoDate = new Date(parseInt(before)).toISOString();
        url += `&iso_timestamp_end=${encodeURIComponent(isoDate)}`;
    }

    console.log(`[LogFetch] Dedicated Endpoint: ${url}`);

    return fetch(url, { 
        headers: { "Authorization": `Bearer ${cloudKey}`, "Content-Type": "application/json" } 
    });
};

let discoveryRes = await fetchLogs();

