 323 | async function genericRequestAI(role: keyof AIConfig['roles'], messages: any[], config?: AIConfig, tools?: any[], responseFormat?: any): Promise<any> {
 324 |   const provider = resolveProvider(role, config);
 325 |   if (!provider) throw new Error(`No provider found for role: ${role}`);
