 334 |   // 2. Persistent DB Log
 335 |   // We use a try-catch to ensure logging failure doesn't block the actual AI request
 336 |   try {
 337 |       await supabase.from('conduit_logs').insert({
 338 |           repo_name: 'DEBUG_TRACE', // Utility function doesn't know repo, using placeholder
 339 |           type: 'ai_prompt_dump',
 340 |           data: { 
