 347 |       });
 348 |   } catch (e) { console.error("Background log failed:", e); }
 349 |   
 350 |   // Advanced Rotation Logic: Fetch Least-Recently-Used key from 'api_keys' table
 351 |   const serviceMap: Record<string, string> = { 
 352 |       'Deepseek_API': 'deepseek', 
 353 |       'GEMINI_API_KEY': 'gemini', 
 354 |       'GROQ_API_KEY': 'groq' 
 355 |   };
 356 |   const serviceName = serviceMap[provider.apiKeyEnv];
 357 |   let apiKey = "";
 358 | 
 359 |   if (serviceName) {
 360 |       const { data: keyRow } = await supabase
 361 |           .from('api_keys')
 362 |           .select('id, api_key')
 363 |           .eq('service', serviceName)
 364 |           .eq('is_active', true)
 365 |           .or(`cooldown_until.is.null,cooldown_until.lt.${new Date().toISOString()}`)
 366 |           .order('last_used_at', { ascending: true, nullsFirst: true })
 367 |           .limit(1)
 368 |           .maybeSingle();
 369 | 
 370 |       if (keyRow) {
 371 |           apiKey = keyRow.api_key;
 372 |           // Mark as used immediately to move it to the end of the rotation queue
 373 |           await supabase.from('api_keys').update({ last_used_at: new Date().toISOString() }).eq('id', keyRow.id);
 374 |       }
 375 |   }
 376 | 
 377 |   // Fallback to Env Var if no key found in DB or service not mapped
 378 |   if (!apiKey) {
 379 |       apiKey = Deno.env.get(provider.apiKeyEnv) || "";
 380 |       if (!apiKey) {
 381 |           if (provider.apiKeyEnv && provider.apiKeyEnv.length > 10) apiKey = provider.apiKeyEnv;
 382 |           else throw new Error(`Missing API Key: No active keys for '${serviceName || provider.apiKeyEnv}' in DB or Env`);
 383 |       }
 384 |   }
