 393 |     };
 394 | 
 395 |     // ADAPTER: Google Strict Function Calling
 396 |     if (tools && tools.length > 0 && messages[0].content.includes('STRICT')) {
 397 |         payload.tool_config = {
 398 |             function_calling_config: {
 399 |                 mode: "ANY",
 400 |                 allowed_function_names: [tools[0].function.name]
 401 |             }
 402 |         };
 403 |     }
 404 | 
 405 |     // MAP OPENAI TOOLS TO GOOGLE FUNCTION DECLARATIONS
 406 |     if (tools && tools.length > 0) {
