 883 | // Helper: Finds code block ignoring whitespace, tabs, newlines, and quote styles
 884 | function findBlockRobust(originalContent: string, searchBlock: string): { start: number; end: number } | null {
 885 |   if (!searchBlock || !originalContent) return null;
 886 | 
 887 |   const createFingerprint = (str: string) => {
 888 |     let clean = "";
 889 |     const map: number[] = [];
 890 |     for (let i = 0; i < str.length; i++) {
 891 |       if (!/\s/.test(str[i])) {
 892 |         clean += str[i];
 893 |         map.push(i);
 894 |       }
 895 |     }
 896 |     return { clean, map };
 897 |   };
 898 | 
 899 |   const fileFP = createFingerprint(originalContent);
 900 |   const searchFP = createFingerprint(searchBlock);
 901 | 
 902 |   // 1. Strict Structural Match
 903 |   let matchIndex = fileFP.clean.indexOf(searchFP.clean);
 904 | 
 905 |   // 2. Quote-Agnostic Fallback (e.g. " vs ')
 906 |   if (matchIndex === -1) {
 907 |     const normalizeQuotes = (s: string) => s.replace(/['"`]/g, '"');
 908 |     matchIndex = normalizeQuotes(fileFP.clean).indexOf(normalizeQuotes(searchFP.clean));
 909 |   }
 910 | 
 911 |   if (matchIndex === -1) return null;
 912 | 
 913 |   const start = fileFP.map[matchIndex];
 914 |   const end = fileFP.map[matchIndex + searchFP.clean.length - 1] + 1;
 915 |   return { start, end };
 916 | }
